// Normalize external payload to work_item schema
const payload = $input.first().json;
const crypto = require('crypto');

const workItem = {
  sourcePlatform: payload.source || payload.platform || 'unknown',
  sourceEventType: payload.event_type || payload.type || 'unknown',
  externalId: payload.id || payload.external_id || crypto.randomUUID(),
  externalUrl: payload.url || payload.html_url || '',
  title: payload.title || payload.subject || 'Untitled Work Item',
  summary: payload.body || payload.description || payload.summary || '',
  rawPayloadRef: `s3:inbound/${workItem.sourcePlatform}/${workItem.externalId}.json`,
  receivedAt: new Date().toISOString(),
  dedupeKey: `${payload.source || 'unknown'}:${payload.id || crypto.randomUUID()}`,
  targetRepo: payload.target_repo || 'OpenSIN-AI/OpenSIN-Code',
  labels: payload.labels || [],
  priority: payload.priority || 'medium',
  riskLevel: payload.risk_level || 'low',
  automationPolicy: payload.automation_policy || 'issue_only',
  watcherRequired: payload.watcher_required || true,
  issueNumber: null,
  prNumber: null
};

return { json: workItem };

// Deduplication check
const workItem = $input.first().json;
const dedupeKey = workItem.dedupeKey;

// In production: query Supabase sin_platform_cursors table
// For now: pass through (dedup handled by cursor tracking)
workItem._dedupeStatus = 'new';

return { json: workItem };

// Signature verification
const workItem = $input.first().json;
const headers = $input.first().headers || {};

// GitHub webhook signature verification
if (workItem.sourcePlatform === 'github') {
  const signature = headers['x-hub-signature-256'] || headers['x-hub-signature'];
  if (signature) {
    // In production: verify HMAC signature
    workItem._signatureVerified = true;
  } else {
    workItem._signatureVerified = false;
    workItem._riskLevel = 'high';
  }
} else {
  workItem._signatureVerified = true; // Skip for non-GitHub
}

return { json: workItem };

