// Update work_item with issue number and store in Supabase
const workItem = $input.first().json;
const issue = $input.first().json.issue || {};

workItem.issueNumber = issue.number || null;
workItem.issueUrl = issue.html_url || null;
workItem._status = 'issue_created';
workItem._updatedAt = new Date().toISOString();

// In production: insert into Supabase sin_issues_pool
// INSERT INTO sin_issues_pool (work_item) VALUES ($1)

return { json: workItem };

// Route to appropriate A2A Coder Agent based on coder-dispatch-matrix.json
const workItem = $input.first().json;
const labels = workItem.labels || [];
const title = (workItem.title || '').toLowerCase();

let assignedAgent = 'A2A-SIN-Code-Integration'; // Default fallback

// Simple routing based on labels/title
if (labels.includes('plugin') || title.includes('plugin') || title.includes('hook')) {
  assignedAgent = 'A2A-SIN-Code-Integration';
} else if (labels.includes('ui') || labels.includes('frontend') || title.includes('component')) {
  assignedAgent = 'A2A-SIN-Frontend';
} else if (labels.includes('ai') || labels.includes('agent') || title.includes('agent')) {
  assignedAgent = 'A2A-SIN-Code-AI';
} else if (labels.includes('backend') || labels.includes('service')) {
  assignedAgent = 'A2A-SIN-Backend';
} else if (labels.includes('database') || labels.includes('migration')) {
  assignedAgent = 'A2A-SIN-Code-Database';
}

workItem.assignedAgent = assignedAgent;
workItem._status = 'dispatched';

return { json: workItem };
